t=Each room is designed by a different artist. Very friendly staff, delicious breakfast. Shared kitchen available after breakfast hours. }} * {{sleep | name=Motel One Brussels | alt= | url=https://www.motel-one.com/en/hotels/brussels/hotel-brussels/ | email= | address= | lat=50.848689 | long=4.363118 | directions= | phone=+32 2 20961 10 | tollfree= | checkin= | checkout= | price= | wikidata=Q133874171 | lastedit=2025-04-15 | content= }}
