92594408989 | 50.8387224,4.3659263 | 50.8387015,4.3648325 | 50.8386837,4.3636899 | 50.8386595,4.3627752 | 50.838873418517025,4.362486314035154 | 50.84020223023784,4.365059126615525 | 50.840574859432344,4.365659941434861 | 50.841130410160496,4.366228569746018 | 50.846530777451186,4.369160780950929 | 50.84701513391653,4.369379774307855 | 50.84361676414604,4.3866991782188425 }}
