49778183,4.375326622724534 | 50.87090366768583,4.3771505248546605 | 50.870172432325134,4.378995884656907 | 50.86894691707437,4.380862691402436 | 50.867592711623395,4.38174245595932 | 50.86423411234248,4.382042863368989 }}
